import React, { useState } from 'react';
import Select from 'react-select';

import './AddMaterial.css';

const AddMaterial = ({ handleAdd, vendors }) => {
  const [newMaterial, setNewMaterial] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: null,
  });


  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewMaterial((prevMaterial) => ({
      ...prevMaterial,
      [name]: value,
    }));
  };

  const handleVendorChange = (selectedOption) => {
    setNewMaterial((prevMaterial) => ({
      ...prevMaterial,
      recent_vendor: selectedOption,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAdd(newMaterial);
    resetForm();
  };

  const resetForm = () => {
    setNewMaterial({
      matid: '',
      name: '',
      description: '',
      unit_of_measure: '',
      price_per_unit: 0,
      recent_vendor: null,
    });
  };

  const openPopupWindow = () => {
    const popupWindow = window.open('', '_blank', 'width=400,height=200');
  
    popupWindow.document.write(`
      <html>
        <head>
          <title>Add Vendor</title>
          <style>
            body {
              font-family: Arial, sans-serif;
              padding: 20px;
            }
  
            h3 {
              margin-top: 0;
            }
  
            button {
              padding: 10px 20px;
              background-color: #007bff;
              color: #fff;
              border: none;
              cursor: pointer;
            }
          </style>
        </head>
        <body>
          <h3>Add Vendor</h3>
          <button id="closeButton">Close</button>
  
          <script>
            const closeButton = window.opener.document.getElementById('recent_vendor');
  
            document.getElementById('closeButton').addEventListener('click', () => {
              const selectedValue = 'Selected Vendor'; // Replace with the actual selected value
  
              closeButton.value = selectedValue;
              window.close();
            });
          </script>
        </body>
      </html>
    `);
  };
  
  

  return (
    <div className="add-material-container">
      <h2 className="add-material-heading">Add Material</h2>
      <form className="add-material-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="matid">Material ID:</label>
            <input
              type="text"
              id="matid"
              name="matid"
              value={newMaterial.matid}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="name">Name:</label>
            <input
              type="text"
              id="name"
              name="name"
              value={newMaterial.name}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="description">Description:</label>
            <textarea
              id="description"
              name="description"
              value={newMaterial.description}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="unit_of_measure">Unit of Measure:</label>
            <input
              type="text"
              id="unit_of_measure"
              name="unit_of_measure"
              value={newMaterial.unit_of_measure}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="price_per_unit">Price per Unit:</label>
            <input
              type="number"
              id="price_per_unit"
              name="price_per_unit"
              value={newMaterial.price_per_unit}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
              <label htmlFor="recent_vendor" className="vendor-label">
                Recent Vendor:
                <button type="button" className="add-vendor-link" onClick={openPopupWindow}>
                  +
                </button>
              </label>
            <Select
              id="recent_vendor"
              name="recent_vendor"
              value={newMaterial.recent_vendor}
              onChange={handleVendorChange}
              options={vendors.map((vendor) => ({ value: vendor.vendorid, label: vendor.name }))}
              isClearable={true}
              placeholder="Select a vendor"
              required
            />
          </div>
        </div>
        <button type="submit" className="add-material-btn">
          Add
        </button>
      </form>
    </div>
  );
};

export default AddMaterial;
